package com.xwc.open.easybatis.core;import com.xwc.open.easybatis.core.enums.IdType;import com.xwc.open.easybatis.core.interfaces.SqlSourceGenerator;import com.xwc.open.easybatis.core.mysql.MysqlSqlSourceGenerator;import org.apache.ibatis.builder.SqlSourceBuilder;import org.apache.ibatis.session.Configuration;import java.util.HashSet;import java.util.Set;public class EasybatisConfiguration {    private Configuration configuration;    /**     * 如果 tablePrefix 有值就默认开启根据类名映射标明     */    private String tablePrefix;    private IdType idType;    protected final Set<String> loadedResources = new HashSet<>();    private final AnnotationAssistant annotationAssistant;    private final SqlSourceGenerator sqlSourceGenerator;    public EasybatisConfiguration(Configuration configuration) {        this.configuration = configuration;        this.annotationAssistant = new AnnotationAssistant(this);        this.sqlSourceGenerator = new MysqlSqlSourceGenerator();    }    public boolean isUseActualParamName() {        return configuration.isUseActualParamName();    }    public boolean isMapUnderscoreToCamelCase() {        return configuration.isMapUnderscoreToCamelCase();    }    public IdType useGlobalPrimaKeyType() {        return idType;    }    public Configuration getMybatisConfiguration() {        return configuration;    }    public void setMybatisConfiguration(Configuration configuration) {        this.configuration = configuration;    }    public String getTablePrefix() {        return tablePrefix;    }    public void setTablePrefix(String tablePrefix) {        this.tablePrefix = tablePrefix;    }    public IdType getIdType() {        return idType;    }    public void setIdType(IdType idType) {        this.idType = idType;    }    public void addMapper(Class<?> mapperClass) {        EasybatisMapperAnnotationBuilder easybatisMapperAnnotationBuilder = new EasybatisMapperAnnotationBuilder(this, mapperClass);        easybatisMapperAnnotationBuilder.parse();    }    public AnnotationAssistant getAnnotationAssistant() {        return annotationAssistant;    }    public boolean isResourceLoaded(String resource) {        return this.loadedResources.contains(resource);    }    public void addLoadedResource(String resource) {        this.loadedResources.add(resource);    }    public SqlSourceGenerator getSqlSourceGenerator() {        return sqlSourceGenerator;    }}